+#[test]
+fn index_parses_semantic_flags() {
+    let cli = Cli::try_parse_from([
+        "cass",
+        "index",
+        "--semantic",
+        "--embedder",
+        "fastembed",
+    ])
+    .expect("parse index flags");
+
+    match cli.command {
+        Some(Commands::Index {
+            semantic, embedder, ..
+        }) => {
+            assert!(semantic, "semantic flag should be true");
+            assert_eq!(embedder, "fastembed");
+        }
+        other => panic!("expected index command, got {other:?}"),
+    }
+}
